  @state uiSize = gui.fontSize.ui  @ 19
  @state toolbar = chrome.makeToolbar()  @ 23   -- one shared toolbar; renders the active page's row
  @state facades = {}  @ 34
  @state facade = {  @ 35
  @state STD = { cm = cm, ds = ds, eventMeta = eventMeta, cmgr = cmgr, c...  @ 39
  @state CHROME_PAD_X, CHROME_PAD_Y = 8, 4  @ 41
  @state pages, active, previous = {}, nil, nil  @ 43
  @state lastToolbarActive = nil  @ 44   -- last page measured; a switch re-pins the band height
  @state bootSettled = false  @ 45   -- latched once boot transients (fonts, window width) settle
  @state bootFrames = 0  @ 46
  @state lastAvailW = nil  @ 47
  @state quitting = false  @ 48
  @state errHandler = nil  @ 49
  @state focusFrames = 0  @ 50   -- >0: re-focus our window this many frames, counting down
  @state fxFloatOpen = false  @ 51   -- an FX float window was open at the last poll
  @state weHadFocus = false  @ 52   -- our window held focus at the end of the last frame
  @state myHwnd  @ 53   -- our OS window HWND, captured via js while we hold focus
  @state jsFocus = reaper.JS_Window_GetForeground ~= nil  @ 54   -- js_ReaScriptAPI present
  @state switcherSeg = { id = 'switcher', render = drawSwitcher }  @ 94
  @state externalCommands = {}  @ 109   -- list of { extKey, command }
  @state coord = {}  @ 284
      @contract  register instantiates page; first registered becomes active; returns page handle

# Private functions
  -- Coordinator
  @fn tick()  @ 59-66
      @contract  tick() runs once per frame before the page draws; no selection bus here
  @fn drawSwitcher()  @ 68-90
  @fn dispatch(state)  @ 96-103
  -- External commands (REAPER-keymap bridge)
  @fn pollExternalCommands()  @ 111-118
  @fn anyFxFloating()  @ 122-134
      -- Any floating FX window open across master + tracks. The poll in frame() reads
      -- its open→closed edge (X button or F11) to reclaim OS focus from REAPER.
  @fn frame()  @ 136-278

# Public API (coord:*)
  @api coord:register(name, moduleName, extra)  @ 286-291
  @api coord:setActive(name)  @ 295-308
      @contract  setActive(name) no-ops if name==active; else unbind outgoing, swap scope, bind incoming
      @contract  tracker's no-arg bind resolves its stored selection; renderBody keeps it current
  @api coord:returnToArrange()  @ 311-314
      @contract  tracker back to arrange; no reveal (cursor never left). No-op if arrange unregistered.
  @api coord:getFacade(name)  @ 317
      @contract  resolve a published page facade by name; the contents are owned by the publishing page
  @api coord:previousPage()  @ 320
      @contract  the page active immediately before the current one; closeEditor returns here
  @api coord:togglePage()  @ 324-332
      -- Cycle tracker → arrange → sample → wiring → tracker. Unregistered pages
      -- are skipped; with ≥1 track every page activates.
  @api coord:reloadAfterExternalMutation()  @ 335-339
      @contract  invoke after firing a REAPER action that mutates the bound take from inside a frame (Ctrl-Z, Ctrl-Shift-Z). The watcher's end-of-frame baseline would otherwise absorb the mutation; this reloads now so tm/vm stay coherent with the take.
  @api coord:onExternalCommand(extKey, command)  @ 342-344
      @contract  registers an ExtState key→command bridge polled each frame to fire Continuum commands
  @api coord:quit()  @ 346
  @api coord:run(handler)  @ 348
      @contract  handler wraps every deferred frame; without it, post-frame-1 errors raise raw dialogs

